      top: '20px',
      right: '20px',
      backgroundColor: '#f39c12',
      color: '#fff',
      padding: '15px 25px',
      borderRadius: '30px',
      fontSize: '15px',
      fontWeight: 500,
      zIndex: 2000,
      boxShadow: '0 5px 20px rgba(243, 156, 18, 0.3)'
    },
    authorInput: {
      display: 'flex',
      gap: '10px',
      marginBottom: '10px'
    },
    removeAuthor: {
      padding: '0 15px',
      backgroundColor: '#e74c3c',
      color: '#fff',
      border: 'none',
      borderRadius: '10px',
      cursor: 'pointer',
      fontSize: '18px'
    },
    addAuthorBtn: {
      marginTop: '10px',
      padding: '8px 20px',
      backgroundColor: '#27ae60',
      color: '#fff',
      border: 'none',
      borderRadius: '20px',
      cursor: 'pointer',
      fontSize: '14px'
    },
    fileInput: {
      width: '100%',
      padding: '10px',
      border: '2px solid #ffe6cc',
      borderRadius: '10px',
      fontSize: '14px'
    },
    loadingSpinner: {
      display: 'inline-block',
      width: '20px',
      height: '20px',
      border: '3px solid #ffe6cc',
      borderTop: '3px solid #f39c12',
      borderRadius: '50%',
      animation: 'spin 1s linear infinite',
      marginRight: '10px'
    },
    successMessage: {
      backgroundColor: '#27ae60',
      color: '#fff',
      padding: '15px',
      borderRadius: '10px',
      marginBottom: '20px',
      textAlign: 'center'
    },
