      fontSize: '12px',
      marginTop: '5px',
      display: 'block'
    }
  };
  
  // Добавляем анимацию
  const styleSheet = document.createElement("style");
  styleSheet.textContent = `
    @keyframes spin {
      0% { transform: rotate(0deg); }
      100% { transform: rotate(360deg); }
    }
  `;
  document.head.appendChild(styleSheet);
  
  return (
    <div style={styles.app}>
