                    draggable={!loading}
                    onDragStart={() => handleDragStart(index)}
                    onDragOver={(e) => {
                      e.preventDefault();
                      handleDragOver(index);
                    }}
                    onDragEnd={handleDragEnd}
                    onDragLeave={() => setDragOverBlockIndex(null)}
                  >
                    <div style={styles.blockHeader}>
                      <div style={{ display: 'flex', alignItems: 'center' }}>
                        <span style={styles.dragHandle}>⋮⋮</span>
                        <span style={styles.blockType}>
                          {block.type === 'text' ? '📝 Текст' :
                           block.type === 'table' ? '📊 Таблица' :
                           block.type === 'image' ? '🖼️ Рисунок' : '🧮 Формула'} • Блок {index + 1}
                          {editingBlock?.id === block.id && ' (ред.)'}
                        </span>
                      </div>
                      <div style={{ display: 'flex', alignItems: 'center' }}>
                        <div style={styles.moveButtons}>
                          <button
                            type="button"
                            style={styles.moveButton}
                            onClick={() => moveBlockUp(index)}
                            disabled={index === 0 || loading}
                          >
                            ↑
                          </button>
                          <button
                            type="button"
                            style={styles.moveButton}
                            onClick={() => moveBlockDown(index)}
                            disabled={index === contentBlocks.length - 1 || loading}
                          >
                            ↓
                          </button>
                        </div>
                        <div style={styles.blockActions}>
                          <button type="button" style={styles.editButton} onClick={(e) => openBlockForEditing(block, e)}>
                            ✏️
                          </button>
                          <button type="button" style={styles.deleteButton} onClick={(e) => deleteBlock(block.id, e)}>
                            ✕
                          </button>
                        </div>
                      </div>
                    </div>
                    
                    {block.type === 'text' && (
                      <div style={{ maxHeight: '100px', overflow: 'hidden' }}>
                        <div dangerouslySetInnerHTML={{ __html: block.content.substring(0, 200) }} />
                        {block.content.length > 200 && <span>...</span>}
                      </div>
                    )}
                    
                    {block.type === 'table' && (
                      <div>
                        <div><strong>{block.caption}</strong></div>
                        <div style={{ fontSize: '14px', color: '#666' }}>
                          Размер: {block.data?.length || 0} × {block.data?.[0]?.length || 0}
                        </div>
                        <div style={{ fontSize: '12px', color: '#999', marginTop: '4px' }}>
                          Таблица {block.number}
                        </div>
                      </div>
                    )}
                    
                    {block.type === 'image' && (
                      <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                        <img
                          src={block.src}
                          alt={block.caption}
                          style={{ width: '60px', height: '60px', objectFit: 'cover', borderRadius: '8px' }}
                        />
                        <div>
                          <div><strong>{block.caption}</strong></div>
                          <div style={{ fontSize: '14px', color: '#666' }}>{block.width}px</div>
                        </div>
                      </div>
                    )}
                    
                    {block.type === 'formula' && (
                      <div>
                        <div><strong>Формула {block.number}</strong></div>
                        <div style={{
                          fontSize: '14px',
                          fontFamily: 'Times New Roman, serif',
                          padding: '10px',
                          backgroundColor: '#fff9f0',
                          borderRadius: '8px',
                          marginTop: '8px'
                        }}>
                          {block.formulaString || block.content}
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
          
          {/* Секция конструкторов */}
          <div style={styles.constructorsSection}>
            <h2 style={styles.sectionTitle}>Создание элементов</h2>
            <div style={styles.constructorsGrid}>
              <div style={styles.constructorCard}>
                <h3 style={styles.cardTitle}>📊 Таблица {tableCounter}</h3>
                <button 
                  type="button" 
                  style={styles.toggleButton} 
                  onClick={() => setIsTableManagerOpen(true)}
                >
                  Создать таблицу
                </button>
              </div>
              <div style={styles.constructorCard}>
                <h3 style={styles.cardTitle}>🖼️ Рисунок {imageCounter}</h3>
                <button 
                  type="button" 
                  style={styles.toggleButton} 
                  onClick={() => setIsImageManagerOpen(true)}
                >
                  Загрузить рисунок
                </button>
              </div>
              <div style={styles.constructorCard}>
                <h3 style={styles.cardTitle}>🧮 Формула {formulaCounter}</h3>
                <button 
                  type="button" 
                  style={styles.toggleButton} 
                  onClick={() => setIsFormulaManagerOpen(true)}
                >
                  Создать формулу
                </button>
              </div>
            </div>
          </div>

          {/* Список литературы */}
<div style={styles.formGroup}>
  <label style={styles.label}>Список литературы</label>
  <textarea
    value={literature}
    onChange={(e) => setLiterature(e.target.value)}
    rows="6"
    style={styles.textarea}
    placeholder={`Пример оформления:
1. Иванов И.И. Название книги. - М.: Издательство, 2024. - 300 с.
2. Петров П.П. Название статьи // Журнал. - 2023. - №5. - С. 10-15.
3. Сидоров С.С. Название // Сборник трудов конференции. - 2022. - С. 100-105.`}
    disabled={loading}
  />
  <div style={{ fontSize: '12px', color: '#999', marginTop: '5px' }}>
    Оформите список литературы в соответствии с ГОСТ
  </div>
</div>

          {/* Дополнительная информация */}
          <div style={styles.formGroup}>
            <label style={styles.label}>Дополнительная информация</label>
            <textarea
              name="additionalInfo"
              value={formData.additionalInfo}
              onChange={handleChange}
              rows="3"
              style={styles.textarea}
              placeholder="Любая дополнительная информация для организаторов"
              disabled={loading}
            />
          </div>
          
          {/* Кнопки сохранения */}
          <div style={styles.saveButtons}>
            <button type="button" onClick={saveDraft} style={styles.draftButton}>
              💾 Сохранить черновик
            </button>
          </div>
          
          {/* Основные кнопки */}
          <div style={styles.mainButtons}>
            <button type="button" onClick={() => setShowPreview(true)} style={styles.previewButton}>
              👁️ Предпросмотр
            </button>
            <button type="button" onClick={() => {
              if (window.confirm('Очистить все поля?')) {
                setArticle({ annotation: '', keywords: '' });
                setContentBlocks([]);
                setCurrentText('');
                setTableCounter(1);
                setImageCounter(1);
                setFormulaCounter(1);
                setFormData({ title: '', conferenceId: '', sectionId: '', authors: [''], additionalInfo: '' });
                setReportFile(null);
                setLiterature('');
                setEditingBlock(null);
                localStorage.removeItem('articleDraft');
              }
            }} style={styles.clearButton}>
              ✖ Очистить
            </button>
            <button type="submit" style={styles.submitButton} disabled={loading || loadingConferences}>
              {loading ? 'Отправка...' : '📤 Отправить доклад'}
            </button>
          </div>
          
          {errors.content && <span style={styles.errorMessage}>{errors.content}</span>}
        </form>
      ) : (
  <div style={styles.previewContainer}>
    <h2 style={styles.previewTitle}>Научная статья</h2>
    
    {/* ✅ Добавьте название конференции, если выбрана */}
    {formData.conferenceId && conferenceTemplate && (
      <div style={styles.previewSection}>
        <div style={styles.previewLabel}>Конференция</div>
        <div>{conferences.find(c => c.id === parseInt(formData.conferenceId))?.title || 'Не указана'}</div>
      </div>
    )}
    
    {/* ✅ Применяем стили из шаблона к авторам */}
    <div style={styles.previewSection}>
      <div style={styles.previewLabel}>Авторы</div>
      <div style={conferenceTemplate?.styles?.authors}>
        {formData.authors.filter(a => a.trim()).join(', ') || 'Не указаны'}
      </div>
    </div>
    
    {/* ✅ Применяем стили из шаблона к аннотации */}
    <div style={styles.previewSection}>
      <div style={styles.previewLabel}>Аннотация</div>
      <div style={conferenceTemplate?.styles?.abstract}>
        {article.annotation || 'Аннотация отсутствует'}
      </div>
    </div>
    
    {/* ✅ Применяем стили из шаблона к ключевым словам */}
    {article.keywords && (
      <div style={styles.previewSection}>
        <div style={styles.previewLabel}>Ключевые слова</div>
        <div style={conferenceTemplate?.styles?.keywords}>
          {article.keywords}
        </div>
      </div>
    )}
    
    {/* ✅ Применяем стили из шаблона к содержанию */}
    <div style={styles.previewSection}>
      <div style={styles.previewLabel}>Содержание</div>
      <div style={conferenceTemplate?.styles?.content}>
        {contentBlocks.length > 0 ? (
          contentBlocks.map((block) => {
            switch (block.type) {
              case 'text':
                return (
                  <div key={block.id} style={{ margin: '20px 0', ...(conferenceTemplate?.styles?.textBlock || {}) }}>
                    <div dangerouslySetInnerHTML={{ __html: block.content }} />
                  </div>
                );
              case 'table':
                return (
                  <div key={block.id}>
                    <div style={conferenceTemplate?.styles?.tableCaption}>
                      Таблица {block.number} — {block.caption}
                    </div>
                    <div style={{ overflowX: 'auto' }}>
                      <table style={{ 
                        borderCollapse: 'collapse', 
                        width: '100%',
                        ...(conferenceTemplate?.styles?.table || {})
                      }}>
                        <thead>
                          <tr>
                            {block.headers?.map((header, i) => (
                              <th key={i} style={{ 
                                border: '1px solid black', 
                                padding: '8px',
                                ...(conferenceTemplate?.styles?.tableHeader || {})
                              }}>{header}</th>
                            ))}
                          </tr>
                        </thead>
                        <tbody>
                          {block.data?.map((row, i) => (
                            <tr key={i}>
                              {row.map((cell, j) => (
                                <td key={j} style={{ 
                                  border: '1px solid black', 
                                  padding: '8px',
                                  ...(conferenceTemplate?.styles?.tableCell || {})
                                }}>{cell}</td>
                              ))}
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  </div>
                );
              case 'image':
                return (
                  <div key={block.id} style={{ textAlign: block.align, margin: '30px 0' }}>
                    <img src={block.src} alt={block.caption} style={{ maxWidth: '100%', width: block.width }} />
                    <div style={{ 
                      marginTop: '8px', 
                      fontSize: '12px', 
                      color: '#666',
                      ...(conferenceTemplate?.styles?.figureCaption || {})
                    }}>
                      Рисунок {block.number} — {block.caption}
                    </div>
                  </div>
                );
              case 'formula':
                return (
                  <div key={block.id} style={{ 
                    textAlign: block.align || 'center', 
                    margin: '30px 0', 
                    fontSize: block.size || 16,
                    ...(conferenceTemplate?.styles?.formula || {})
                  }}>
                    <strong>Формула {block.number}:</strong> {block.formulaString || block.content}
                  </div>
                );
              default:
                return null;
            }
          })
        ) : (
          <div style={styles.emptyState}>Содержание статьи пусто</div>
        )}
      </div>
    </div>
    
    {/* ✅ Применяем стили из шаблона к литературе */}
    {literature && (
      <div style={styles.previewSection}>
        <div style={styles.previewLabel}>Список литературы</div>
        <div style={{ 
          whiteSpace: 'pre-wrap', 
          fontSize: '14px', 
          lineHeight: '1.5',
          ...(conferenceTemplate?.styles?.references || {})
        }}>
          {literature}
        </div>
      </div>
    )}
    
    <div style={{ marginTop: '30px', textAlign: 'center' }}>
      <button onClick={() => setShowPreview(false)} style={styles.previewButton}>
        ← Вернуться к редактированию
      </button>
    </div>
  </div>
)}
      {/* Модальные окна */}
      <TableManager
        isOpen={isTableManagerOpen}
        onClose={() => {
          setIsTableManagerOpen(false);
          if (editingBlock?.type === 'table') setEditingBlock(null);
        }}
        onSave={handleSaveTable}
        editingBlock={editingBlock?.type === 'table' ? editingBlock : null}
        tableCounter={tableCounter}
      />
      
      <ImageManager
        isOpen={isImageManagerOpen}
        onClose={() => {
          setIsImageManagerOpen(false);
          if (editingBlock?.type === 'image') setEditingBlock(null);
        }}
        onSave={handleSaveImage}
        editingBlock={editingBlock?.type === 'image' ? editingBlock : null}
        imageCounter={imageCounter}
      />
      
      <FormulaManager
        isOpen={isFormulaManagerOpen}
        onClose={() => {
          setIsFormulaManagerOpen(false);
          if (editingBlock?.type === 'formula') setEditingBlock(null);
        }}
        onSave={handleSaveFormula}
        editingBlock={editingBlock?.type === 'formula' ? editingBlock : null}
        formulaCounter={formulaCounter}
      />
    </div>
  );
};
 

export default SubmitReport;
